(()=>{"use strict";$((function(){if(!$(".tag-cloud").length)return;let t=Number.MAX_VALUE,n=Number.MIN_VALUE;if($(".tag-cloud a").each((function(){const s=0|+$(this).find("sup").text()||1;t=Math.min(t,s),n=Math.max(n,s)})),t>n)return;const s=100/Math.sqrt(n-t+1);$(".tag-cloud a").each((function(){const n=0|+$(this).find("sup").text()||1;$(this).css("font-size",50+Math.sqrt(n-t+1)*s+"%")}))}))})();